import time
from collections.abc import Callable
from typing import Any


def retry(fn: Callable[[], Any], max_attempts: int, delay_seconds: float) -> Any:
    """Call fn with retries using exponential back-off on any exception."""
    if max_attempts < 1:
        raise ValueError("max_attempts must be at least 1")
    attempt = 0
    delay = delay_seconds
    last_exc: BaseException | None = None
    while attempt < max_attempts:
        try:
            return fn()
        except Exception as exc:
            last_exc = exc
            attempt += 1
            if attempt >= max_attempts:
                break
            if delay > 0:
                time.sleep(delay)
                delay *= 2
    assert last_exc is not None
    raise last_exc
